import { ContributionType } from './contribution.type';

/**
 * Aggregate Elasticsearch `contribution` document for a Collabora document
 * edited within a window. Unlike the per-user contribution documents (which
 * carry a single `author` via {@link ContributionAuthorDetails}), this is ONE
 * aggregate document per (document, window) carrying two user arrays:
 * `writeUsers` (write-capable active users) and `readonlyUsers` (read-only
 * active users). See feature 003-collabora-doc-contributions.
 */
export type CollaboraDocumentContributionDocument = {
  /**
   * Id of the CollaboraDocument this report relates to.
   * Not the id of the contribution document itself (generated by Elasticsearch).
   */
  id: string;
  /**
   * Contribution type — always COLLABORA_DOCUMENT_CONTRIBUTION.
   */
  type: ContributionType;
  /**
   * Display name of the CollaboraDocument.
   */
  name: string;
  /**
   * Timestamp.
   */
  '@timestamp': Date;
  /**
   * Environment, obtained from the config hosting.environment.
   */
  environment: string;
  /**
   * Identifier of the level-zero space this contribution belongs to.
   */
  space: string;
  /**
   * Distinct write-capable users active in the edited window.
   */
  writeUsers: { id: string }[];
  /**
   * Distinct read-only users active in the edited window.
   */
  readonlyUsers: { id: string }[];
};
